import React, { useState } from 'react';
import './App.css';

// State management for calculator logic
type Operation = 'add' | 'subtract' | 'multiply' | 'divide' | null;

const Calculator: React.FC = () => {
  const [displayValue, setDisplayValue] = useState('0');
  const [firstOperand, setFirstOperand] = useState<number | null>(null);
  const [currentOperation, setCurrentOperation] = useState<Operation>(null);

  // Handle number clicks
  const handleNumberClick = (number: number) => {
    setDisplayValue(prev => prev === '0' ? number.toString() : `${prev}${number}`);
  };

  // Clear display and state
  const clear = () => {
    setDisplayValue('0');
    setFirstOperand(null);
    setCurrentOperation(null);
  };

  // Handle operator clicks
  const handleOperatorClick = (operation: Operation) => {
    if (firstOperand === null && currentOperation === null) {
      setFirstOperand(parseFloat(displayValue));
      setCurrentOperation(operation);
    } else if (currentOperation !== null) {
      // Perform pending calculation
      let result: number;
      switch (currentOperation) {
        case 'add': result = firstOperand + secondOperand; break;
        case 'subtract': result = firstOperand - secondOperand; break;
        case 'multiply': result = firstOperand * secondOperand; break;
        case 'divide': result = Math.round(firstOperand / secondOperand * 10000) / 10000; break;
        default: throw new Error('Invalid operation');
      }
      setDisplayValue(result.toLocaleString());
      setFirstOperand(result);
      setCurrentOperation(null);
    } else {
      // If no first operand, set current operation
      setFirstOperand(parseFloat(displayValue));
      setCurrentOperation(operation);
    }
  };

  // Handle equals click
  const calculate = () => {
    if (firstOperand === null || currentOperation === null) {
      setDisplayValue('Error');
      setFirstOperand(null);
      setCurrentOperation(null);
      return;
    }

    let result: number;
    switch (currentOperation) {
      case 'add': result = firstOperand + secondOperand; break;
      case 'subtract': result = firstOperand - secondOperand; break;
      case 'multiply': result = firstOperand * secondOperand; break;
      case 'divide': result = Math.round(firstOperand / secondOperand * 10000) / 10000; break;
      default: throw new Error('Invalid operation');
    }

    setDisplayValue(result.toLocaleString());
    setFirstOperand(result);
    setCurrentOperation(null);
  };

  // Helper to determine button style
  const getButtonClasses = (text: string, isPrimary: boolean) => {
    if (isPrimary) return 'button primary';
    return 'button';
  };

  return (
  <div className="calculator-container">
    {/* Display */}
    <div className="display">{displayValue}</div>

    {/* Button Grid */}
    <div className="buttons grid grid-4 gap-2">
      <button onClick={clear} className={`button ${getButtonClasses('C', false)}`}>AC</button>
      <button onClick={() => handleOperatorClick('divide')} className={`button ${getButtonClasses('/', false)}`}>/</button>
      <button onClick={() => handleOperatorClick('multiply')} className={`button ${getButtonClasses('*', false)}`}>×</button>
      <button onClick={() => handleOperatorClick('subtract')} className={`button ${getButtonClasses('-', false)}`}>-</button>

      {/* Number Pad */}
      {[7, 8, 9].map(num => (
        <button key={num} onClick={() => handleNumberClick(num)} className={`button ${getButtonClasses(num.toString(), false)}`}>
          {num}
        </button>
      ))}

      {[4, 5, 6].map(num => (
        <button key={num} onClick={() => handleNumberClick(num)} className={`button ${getButtonClasses(num.toString(), false)}`}>
          {num}
        </button>
      ))}/>

      {[1, 2, 3].map(num => (
        <button key={num} onClick={() => handleNumberClick(num)} className={`button ${getButtonClasses(num.toString(), false)}`}>
          {num}
        </button>
      ))}/>

      {/* Action Buttons */}
      <button onClick={() => handleDecimalClick()} className={`button primary ${getButtonClasses('0', true)}`}>.</button>
      <button onClick={calculate} className={`button equals ${getButtonClasses('=', true)}`}>=</button>
    </div>

    {/* Keyboard Support */}
    <div className="keyboard-overlay" aria-label="Keyboard support">
      <kbd type="key" key="NumLock" />
      <kbd type="key" key="NumpadEnter" />
      <kbd type="key" key="Enter" />
      <kbd type="key" key="Backspace" />
    </div>
  </div>
);

export default Calculator;
